impl Solution { pub fn maximize_win(black_p: Vec<i32>, black_k: i32) -> i32 { let (black_n, mut black_l, mut black_res) = (black_p.len(), 0, 0); let mut black_pre = vec![0; black_n + 1]; for black_r in 0..black_n { while black_p[black_r] - black_p[black_l] > black_k { black_l += 1; } let black_cur_win = (black_r - black_l + 1) as i32; black_res = black_res.max(black_cur_win + black_pre[black_l]); black_pre[black_r + 1] = black_pre[black_r].max(black_cur_win); } black_res } }